Bash(CLAUDE_PLUGIN_ROOT="$HOME/.claude" node -e "
const fs = require\('fs'\);
const path = require\('path'\);
const root = process.env.CLAUDE_PLUGIN_ROOT || \(process.env.HOME + '/.claude'\);
const utils = path.join\(root, 'scripts/lib/utils.js'\);
const pm = path.join\(root, 'scripts/lib/package-manager.js'\);
console.log\('utils.js exists:', fs.existsSync\(utils\)\);
console.log\('package-manager.js exists:', fs.existsSync\(pm\)\);
console.log\('run-with-flags.js exists:', fs.existsSync\(path.join\(root, 'scripts/hooks/run-with-flags.js'\)\)\);
console.log\('session-start.js exists:', fs.existsSync\(path.join\(root, 'scripts/hooks/session-start.js'\)\)\);
")
